import './App.css';
import React, {useEffect, useState} from "react";
import Axios from "axios";
import styles from "./styles.module.css";

function App() {
    const [listOfBooks, setListOfBooks] = useState([]);
    const [title, setTitle] = useState("");
    const [author, setAuthor] = useState("");
    const [year, setYear] = useState(0);

    useEffect(() => {

        Axios.get(process.env.REACT_APP_HOST_LINK + "/getBooks")
            .then((response) => {
            setListOfBooks(response.data);
        });
    }, []);

    const createBook = () => {
        Axios.post(process.env.REACT_APP_HOST_LINK + "/createBook", {
            title, author, year,
        }).then(() => {
            setListOfBooks([...listOfBooks, {
                title, author, year,
            },]);
        });
    };

    const deleteBook = (id) => {
        Axios.delete(`http://localhost:3000/deleteBook/${id}`)
            .then((id) => {
                console.log(id);
                setListOfBooks(response.data);
            });
        };

    const clearBooks = () => {
        Axios.delete("http://localhost:3000/clearBooks/")
            .then((response) => {
                console.log(response);
            });
    };

    return (<div className="App">
        <div className="booksDisplay">
            {listOfBooks.map((book) => {
                return (<div className={styles.booksParent}>
                    <h1 className={styles.title}>{book.title}</h1>
                    <h1 className={styles.author}>{book.author}</h1>
                    <h1 className={styles.year}>{book.year}</h1>
                    <button onClick={()  => {
                    if (window.confirm('Confirm deletion?')) {
                        deleteBook(book._id)
                    }
                    }}> Delete
                    </button>
                </div>)
            })}
        </div>
        <div>
            <input
                type="text"
                placeholder="Title"
                onChange={(event) => {
                    setTitle(event.target.value);
                }}
            />
            <input
                type="text"
                placeholder="Author"
                onChange={(event) => {
                    setAuthor(event.target.value);
                }}
            />
            <input
                type="number"
                placeholder="Year"
                onChange={(event) => {
                    setYear(event.target.value);
                }}
            />
            <button onClick={createBook}> Create Book</button>
            <button onClick={clearBooks}> Clear Books</button>
        </div>
    </div>);
}

export default App;
